import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../../services/api';

function MarkAttendance({ user }) {
  const [attendanceData, setAttendanceData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [markTime, setMarkTime] = useState(null); // New state for marking time
  const navigate = useNavigate();

  useEffect(() => {
    const checkAttendance = async () => {
      try {
        const response = await api.get('/attendance/');
        setAttendanceData(response.data);
        
        // Check if attendance is already marked and get the time
        if (response.data.already_marked) {
          // You'll need to fetch the actual attendance record with timestamp
          fetchAttendanceTime();
        }
      } catch (err) {
        setError('Failed to load attendance data');
      } finally {
        setLoading(false);
      }
    };   
    checkAttendance();
  }, []);

  // New function to fetch the exact attendance time
  const fetchAttendanceTime = async () => {
    try {
      // You might need to create a new endpoint or modify existing one
      // For now, we'll use a separate endpoint to get today's attendance details
      const response = await api.get('/attendance/today/');
      if (response.data) {
        setMarkTime(response.data.marked_at || response.data.created_at);
      }
    } catch (err) {
      console.log('Could not fetch attendance time');
    }
  };

  const handleMarkAttendance = async () => {
    setSubmitting(true);
    setError('');
    
    try {
      const response = await api.post('/attendance/');
      
      // Get the current time when attendance is marked
      const now = new Date();
      setMarkTime(now.toISOString());
      
      // Update attendance data
      setAttendanceData({
        ...attendanceData,
        already_marked: true
      });
      
      // Optional: Show success message for 2 seconds before redirecting
      setTimeout(() => {
        if (user.is_admin) {
          navigate('/admin');
        } else {
          navigate('/dashboard');
        }
      }, 2000);
      
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to mark attendance');
    } finally {
      setSubmitting(false);
    }
  };

  const handleBack = () => {
    if (user.is_admin) {
      navigate('/admin');
    } else {
      navigate('/dashboard');
    }
  };

  const getStatusMessage = () => {
    if (attendanceData?.on_leave) {
      return "You are on Leave today";
    }
    if (attendanceData?.on_wfh) {
      return "You are on Work From Home today";
    }
    if (attendanceData?.already_marked) {
      return "You have already marked attendance today";
    }
    return null;
  };

  // Format the time for display
  const formatMarkTime = (isoString) => {
    if (!isoString) return '';
    const date = new Date(isoString);
    return date.toLocaleTimeString('en-US', { 
      hour: '2-digit', 
      minute: '2-digit', 
      second: '2-digit',
      hour12: true 
    });
  };

  if (loading) {
    return <div style={styles.loading}>Loading...</div>;
  }

  if (error && !attendanceData?.can_mark) {
    return (
      <div style={styles.container}>
        <div style={styles.card}>
          <h2 style={styles.title}>Mark Attendance</h2>
          <p style={styles.date}>Date: {new Date().toLocaleDateString('en-US', { 
            year: 'numeric', month: 'long', day: 'numeric' 
          })}</p>
          
          <div style={styles.error}>{error}</div>
          
          <button onClick={handleBack} style={styles.backButton}>Back</button>
        </div>
      </div>
    );
  }

  const statusMessage = getStatusMessage();

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h2 style={styles.title}>Mark Attendance</h2>
        <p style={styles.date}>Date: {new Date().toLocaleDateString('en-US', { 
          year: 'numeric', month: 'long', day: 'numeric' 
        })}</p>
        
        {/* Show marking time if attendance is already marked */}
        {attendanceData?.already_marked && markTime && (
          <div style={styles.timeInfo}>
            <p style={styles.timeText}>
              Marked at: <strong>{formatMarkTime(markTime)}</strong>
            </p>
          </div>
        )}
        
        {attendanceData?.can_mark ? (
          <button 
            onClick={handleMarkAttendance} 
            disabled={submitting}
            style={submitting ? {...styles.markButton, ...styles.disabledButton} : styles.markButton}
          >
            {submitting ? 'Marking...' : 'Mark Present'}
          </button>
        ) : (
          <div style={styles.info}>
            <p style={styles.infoText}>{statusMessage}</p>
          </div>
        )}
        
        <button onClick={handleBack} style={styles.backButton}>Back to Dashboard</button>
      </div>
    </div>
  );
}

const styles = {
  container: {
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    minHeight: '100vh',
    padding: '20px',
    backgroundColor: '#f5f5f5',
  },
  card: {
    background: 'white',
    padding: '40px',
    borderRadius: '16px',
    width: '350px',
    textAlign: 'center',
    boxShadow: '0 5px 15px rgba(0,0,0,0.2)',
    border: '2px solid var(--moss-green)',
  },
  title: {
    color: 'var(--moss-dark)',
    fontSize: '28px',
    marginTop: 0,
    marginBottom: '20px',
    fontWeight: 500,
  },
  date: {
    fontSize: '18px',
    color: 'var(--moss-green)',
    backgroundColor: 'var(--moss-pale)',
    padding: '10px',
    borderRadius: '8px',
    marginBottom: '25px',
  },
  timeInfo: {
    marginBottom: '20px',
    padding: '10px',
    backgroundColor: '#d4edda',
    border: '1px solid #c3e6cb',
    borderRadius: '8px',
  },
  timeText: {
    color: '#155724',
    fontSize: '16px',
    margin: 0,
  },
  markButton: {
    padding: '12px 25px',
    backgroundColor: 'var(--moss-green)',
    color: 'white',
    border: '1px solid var(--moss-dark)',
    borderRadius: '8px',
    cursor: 'pointer',
    margin: '10px 5px',
    fontSize: '16px',
    fontFamily: 'Times New Roman, Times, serif',
    transition: '0.2s',
    width: '100%',
  },
  disabledButton: {
    opacity: 0.6,
    cursor: 'not-allowed',
  },
  backButton: {
    padding: '12px 25px',
    backgroundColor: 'var(--moss-pale)',
    color: 'var(--moss-dark)',
    border: '1px solid var(--moss-green)',
    borderRadius: '8px',
    cursor: 'pointer',
    margin: '10px 5px',
    fontSize: '16px',
    fontFamily: 'Times New Roman, Times, serif',
    transition: '0.2s',
    width: '100%',
  },
  error: {
    color: '#a94442',
    backgroundColor: '#f2dede',
    padding: '12px',
    borderRadius: '8px',
    marginBottom: '20px',
    border: '1px solid #ebccd1',
  },
  info: {
    marginBottom: '20px',
  },
  infoText: {
    color: 'var(--moss-dark)',
    backgroundColor: 'var(--moss-pale)',
    padding: '12px',
    borderRadius: '8px',
    fontSize: '16px',
  },
  loading: {
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    height: '100vh',
    fontSize: '20px',
    color: 'var(--moss-dark)',
  },
};

export default MarkAttendance;
